#!/usr/bin/env python3
# apply_boss_art.py  (CORRECTED) — inject the 3 boss card WebP assets
# (Dyefone / Sandroid / Sinsta-Ram) into assets/assets.json.
# Stores RAW base64 (no data: prefix) because the source template already
# carries "data:image/webp;base64," inline before each placeholder.
# Re-running is safe; it overwrites any previous (incorrect) values.
# Usage from repo root:  python3 apply_boss_art.py  &&  python3 build.py
import json, os, sys

root = os.path.dirname(os.path.abspath(__file__))
AJ = os.path.join(root, 'assets', 'assets.json')

# a909=Dyefone, a910=Sandroid, a911=Sinsta-Ram
NEW = {
  "a909": "",
  "a910": "",
  "a911": "",
}

if not os.path.exists(AJ):
    sys.exit("[apply] assets/assets.json not found — run from the repo root.")
assets = json.load(open(AJ))
# guard: strip any accidental data-URI prefix so we never double it
def raw_only(v):
    i = v.find('base64,')
    return v[i+7:] if i != -1 else v
changed = []
for k, v in NEW.items():
    nv = raw_only(v)
    if assets.get(k) != nv:
        assets[k] = nv; changed.append(k)
json.dump(assets, open(AJ, 'w'))
print(f"[apply] boss art -> set {changed or '(already correct)'}")
print("[apply] done. Next: python3 build.py")
